import { api, API_ENDPOINTS } from "./api";
import { Doctor, ApiResponse, PaginatedResponse } from "@/types";

export interface DoctorSearchFilters {
  specialty?: string;
  name?: string;
  clinic?: string;
  location?: string;
  maxFee?: number;
  isAvailable?: boolean;
}

export const doctorService = {
  async getDoctors(
    filters?: DoctorSearchFilters,
    _page = 1,
    _limit = 10
  ): Promise<PaginatedResponse<Doctor>> {
    const params = new URLSearchParams();
    if (filters?.specialty)   params.set("specialty",    filters.specialty);
    if (filters?.name)        params.set("name",         filters.name);
    if (filters?.clinic)      params.set("clinic",       filters.clinic);
    if (filters?.location)    params.set("location",     filters.location);
    if (filters?.maxFee)      params.set("max_fee",      String(filters.maxFee));
    if (filters?.isAvailable) params.set("is_available", "true");
    const query = params.toString() ? `?${params}` : "";
    try {
      const data = await api.get<Doctor[]>(`${API_ENDPOINTS.DOCTORS}${query}`);
      return { data, success: true, page: 1, limit: data.length, total: data.length, totalPages: 1 };
    } catch {
      return { data: [], success: false, page: 1, limit: 0, total: 0, totalPages: 1 };
    }
  },

  async getDoctorById(id: string): Promise<ApiResponse<Doctor>> {
    try {
      const data = await api.get<Doctor>(API_ENDPOINTS.DOCTOR_DETAIL(id));
      return { data, success: true };
    } catch {
      return { data: null as unknown as Doctor, success: false };
    }
  },

  async getTopDoctors(limit = 5): Promise<ApiResponse<Doctor[]>> {
    const res = await this.getDoctors(undefined, 1, limit);
    return { data: res.data.slice(0, limit), success: true };
  },

  async getDoctorsBySpecialty(specialty: string): Promise<ApiResponse<Doctor[]>> {
    const res = await this.getDoctors({ specialty });
    return { data: res.data, success: true };
  },

  async updateOnDemand(id: string, isOnDemand: boolean): Promise<ApiResponse<Doctor>> {
    try {
      const data = await api.patch<Doctor>(API_ENDPOINTS.DOCTOR_DETAIL(id), { is_on_demand: isOnDemand });
      return { data, success: true };
    } catch {
      return { data: null as unknown as Doctor, success: false };
    }
  },
};
